JOIN zip_code ON member.zip = zip_code.zip_code
WHERE first_name = 'Adela' AND last_name = 'O''Gallagher';

SELECT m.major_name
FROM member AS m
WHERE m.first_name = 'Brent' AND m.last_name = 'Thomason';

SELECT major.department AS Department FROM member
JOIN major ON member.link_to_major = major.major_id
WHERE position = 'President';

SELECT DISTINCT income.date_received
FROM member JOIN income ON (member.member_id = income.link_to_member)
WHERE member.first_name = 'Connor' AND member.last_name = 'Hilton' AND income.source = 'Dues';

SELECT COUNT(DISTINCT zip_code) AS hometowns_from_Maryland
FROM member JOIN zip_code ON (member.zip = zip_code.zip_code)
WHERE short_state = 'MD' AND position != 'Executive Member';

SELECT COUNT(event_id) AS num_meeting_events
FROM event
WHERE type = 'Meeting' AND YEAR(event_date) = 2020;

SELECT first_name || ' ' || last_name AS "Student Name", income.source, MAX(income.amount) AS "Highest Income"
FROM member JOIN income ON member.member_id = income.link_to_member
GROUP BY first_name, last_name, income.source;

SELECT AVG(spent) AS "Average Food Spend"
FROM budget
WHERE category = 'Food' AND event_status = 'Closed';

SELECT event_name FROM (
    SELECT link_to_event, MAX(spent) as max_spent FROM budget WHERE category = 'Advertisement' GROUP BY link_to_event
) b INNER JOIN event e ON b.link_to_event = e.event_id;

SELECT e.event_id, e.notes, b.amount, expense.cost
FROM expense INNER JOIN budget AS b ON (b.budget_id = expense.link_to_budget) AND (expense.expense_description = 'Posters')
INNER JOIN event AS e ON (e.event_id = b.link_to_event) WHERE e.notes LIKE '%September Speaker%';

SELECT  b.category, sum(b.amount) AS budgeted_for_event FROM budget AS b
JOIN event AS e ON e.event_id = b.link_to_event
WHERE e.event_name = 'April Speaker' GROUP BY b.category ORDER BY budgeted_for_event ASC;

SELECT COUNT(*)
FROM income
WHERE amount = 50;

SELECT COUNT(member_id)
FROM member
WHERE position = 'Member' AND t_shirt_size = 'X-Large';

SELECT m.last_name, e.department, e.college
FROM member m INNER JOIN major e ON (m.link_to_major = e.major_id)
WHERE e.major_name = 'Environmental Engineering';

SELECT m.phone AS "Phone Number"
FROM member m JOIN major maj ON (m.link_to_major = maj.major_id)
WHERE maj.college = 'College of Agriculture and Applied Sciences' AND maj.major_name = 'Business';

SELECT email FROM member WHERE member_id IN (
    SELECT link_to_member FROM expense WHERE cost > 20 AND expense_date BETWEEN '2019-09-10' AND '2019-11-19'
);

SELECT event.event_name, event.location
FROM event JOIN budget ON event.event_id = budget.link_to_event
WHERE remaining > 0;

SELECT CONCAT(m.first_name, ' ', m.last_name) AS full_name, maj.major_name
FROM member m JOIN major maj ON m.link_to_major = maj.major_id
JOIN expense e ON m.member_id = e.link_to_member AND e.cost > 100;

SELECT (SUM(CASE WHEN state = 'New Jersey' THEN 1 ELSE 0 END) / COUNT(*)) -
       (SUM(CASE WHEN state = 'Vermont'   THEN 1 ELSE 0 END) / COUNT(*)) AS percentage_difference_between_nj_and_vermont_members
FROM member;

SELECT b.category, b.amount
FROM budget AS b JOIN event AS e ON (b.link_to_event = e.event_id)
WHERE e.event_name = 'January Speaker';

SELECT CONCAT(m.first_name, ' ', m.last_name) AS "Student Name", i.amount AS "Funds Received"
FROM member m INNER JOIN income i ON m.member_id = i.link_to_member
WHERE i.date_received = '9/9/2019';

SELECT m.first_name || ' ' || m.last_name AS FullName, mj.college
FROM member m INNER JOIN major mj ON (m.link_to_major = mj.major_id)
WHERE position = 'Secretary';

SELECT zip_code.city AS "Hometown"
FROM member JOIN zip_code ON member.zip = zip_code.zip_code
WHERE member.first_name = 'Garrett' AND member.last_name = 'Gerke';

SELECT AVG(Consumption) AS "Average monthly consumption" FROM yearmonth WHERE Date LIKE '2013%' AND CustomerID IN (
    SELECT CustomerID FROM customers WHERE Segment = 'SME'
);

SELECT Date AS Year, SUM(Price * Consumption) AS Amount_Paid_in_EUR
FROM transactions_1k INNER JOIN yearmonth ON transactions_1k.CustomerID = yearmonth.CustomerID AND transactions_1k.Date = yearmonth.Date
GROUP BY Date ORDER BY Amount_Paid_in_EUR DESC LIMIT 1;

SELECT SUM(Consumption) AS "Total Consumption" 
FROM yearmonth 
WHERE CustomerID = 6 AND Date LIKE '2013%' AND SUBSTR(Date,5,2) BETWEEN '08' AND '11';

SELECT SUM(CASE WHEN CustomerID = 7 THEN Consumption ELSE -Consumption END) AS DifferenceInApril2013
FROM yearmonth
WHERE Date LIKE '2013%' AND (CustomerID = 5 OR CustomerID = 7);

SELECT ROUND(100.0 * COUNT(CASE WHEN Segment = 'Premium' THEN 1 END) / COUNT(*), 2) AS "Percentage of Premium Gas Stations"
FROM gasstations
WHERE Country = 'Slovakia';

SELECT DISTINCT country
FROM gasstations JOIN transactions_1k ON gasstations.GasStationID = transactions_1k.GasStationID
WHERE SUBSTR(date, 0,5)='201306';

SELECT DISTINCT description
FROM products JOIN transactions_1k ON products.ProductID = transactions_1k.ProductID AND transactions_1k.currency = 'EUR'
ORDER BY description;

SELECT DISTINCT Currency
FROM transactions_1k T INNER JOIN customers C ON T.CustomerID = C.CustomerID
WHERE Time = '16:25:00' AND Date = '2012-08-24';

SELECT COUNT(TransactionID) AS Number_of_transactions_in_CZK
FROM transactions_1k
WHERE (Date = '2012-08-26' AND Time < '13:00:00') AND Currency = 'CZK';

SELECT Country FROM transactions_1k AS T1
 JOIN gasstations AS G ON T1.GasStationID = G.GasStationID
 WHERE Date='2012-08-24' AND Time='12:42:00';

SELECT CAST(COUNT(c.CustomerID) * 100 / COUNT(*) AS DECIMAL(4,2)) AS 'EUR Percentage' FROM transactions_1k t
JOIN customers c ON t.CustomerID = c.CustomerID
WHERE currency = 'EUR' AND Date = '2012-08-25';

SELECT COUNT(DISTINCT c.CustomerID) * 100.0 / COUNT(DISTINCT t."TransactionID") AS Percentage_Premium
FROM transactions_1k t JOIN customers c ON t."CustomerID" = c."CustomerID" AND t."Country" = 'SVK'
WHERE c."Segment" = 'premium';

SELECT SUM(t."Amount") AS "Total Amount"
FROM transactions_1k t
WHERE t."CustomerID" = '38508' AND t."Date" LIKE '201201%';
